###############################################################################
# THE KING OF THE FOUR REALMS - A MIPS Adventure Game
# COMP 206 Term Project - Spring 2026
###############################################################################

###############################################################################
# SECTION 1 - CONSTANTS
###############################################################################

    .eqv  IMG_W            128
    .eqv  IMG_H            128
    .eqv  IMG_WORDS        16384

    .eqv  SYS_PRINT_STR    4
    .eqv  SYS_READ_CHAR    12
    .eqv  SYS_PRINT_INT    1
    .eqv  SYS_PRINT_CHAR   11
    .eqv  SYS_EXIT         10
    .eqv  SYS_RAND_RANGE   42
    .eqv  SYS_SLEEP        32

    # Realm IDs
    .eqv  R_VAMP           0
    .eqv  R_MINER          1
    .eqv  R_PRIEST         2
    .eqv  R_LITH           3

    # Stat IDs
    .eqv  S_SPECIAL        0
    .eqv  S_AGGR           1
    .eqv  S_STR            2
    .eqv  S_INFL           3

    # Scene-script control codes (signed two's-complement of 0xE0..0xE4, 0xFF)
    .eqv  ENV_THRONE         -32          # 0xE0
    .eqv  ENV_DREAM          -31          # 0xE1
    .eqv  ENV_CHAMBER        -30          # 0xE2
    .eqv  ENV_LIBRARY        -29          # 0xE3
    .eqv  ENV_GATE           -28          # 0xE4
    .eqv  ENV_END_DELIV      -27          # 0xE5
    .eqv  ENV_END_NIGHT      -26          # 0xE6
    .eqv  ENV_END_RED        -25          # 0xE7
    .eqv  ENV_END_CRYSTAL    -24          # 0xE8
    .eqv  ENV_BLOOD          -23          # 0xE9  (img_blood_drop)
    .eqv  ENV_SHARD          -22          # 0xEA  (img_crystal_shard)
    .eqv  ENV_BLACK          -21          # 0xEB  (img_black_fade)
    .eqv  END_SCENE          -1           # 0xFF

    # Bar IDs
    .eqv  BAR_VAMP_HUNGER    0x00
    .eqv  BAR_VAMP_AGGR      0x01
    .eqv  BAR_VAMP_STR       0x02
    .eqv  BAR_VAMP_INFL      0x03
    .eqv  BAR_MINER_HEALTH   0x10
    .eqv  BAR_MINER_AGGR     0x11
    .eqv  BAR_MINER_STR      0x12
    .eqv  BAR_MINER_INFL     0x13
    .eqv  BAR_PRIEST_FAITH   0x20
    .eqv  BAR_PRIEST_AGGR    0x21
    .eqv  BAR_PRIEST_STR     0x22
    .eqv  BAR_PRIEST_INFL    0x23
    .eqv  BAR_LITH_CRYSTAL   0x30
    .eqv  BAR_LITH_AGGR      0x31
    .eqv  BAR_LITH_STR       0x32
    .eqv  BAR_LITH_INFL      0x33

    # Flag bit masks
    .eqv  F_RAHIP_BACKED    0x01
    .eqv  F_LITHARI_BACKED  0x02
    .eqv  F_VAMP_PATH       0x04
    .eqv  F_RAHIP_PATH      0x08
    .eqv  F_LITHARI_PATH    0x10
    .eqv  F_EDMURE_PATH     0x20
    .eqv  F_BOOK_KEPT       0x40
    .eqv  F_BOOK_BURNED     0x80

###############################################################################
# SECTION 2 - CUSTOM PSEUDO-INSTRUCTIONS (Bar System Macros)
###############################################################################

.macro BARSET (%barID, %val)
    li      $t9, %barID
    li      $at, %val
    bgez    $at, _bs_check_hi
    li      $at, 0
_bs_check_hi:
    ble     $at, 100, _bs_store
    li      $at, 100
_bs_store:
    srl     $t8, $t9, 4
    andi    $t9, $t9, 0xF
    sll     $t8, $t8, 2
    add     $t8, $t8, $t9
    la      $t7, bar_state
    add     $t7, $t7, $t8
    sb      $at, 0($t7)
.end_macro

.macro BARADD (%barID, %delta)
    li      $t9, %barID
    srl     $t8, $t9, 4
    andi    $t9, $t9, 0xF
    sll     $t8, $t8, 2
    add     $t8, $t8, $t9
    la      $t7, bar_state
    add     $t7, $t7, $t8
    lbu     $at, 0($t7)
    addi    $at, $at, %delta
    ble     $at, 100, _ba_store
    li      $at, 100
_ba_store:
    sb      $at, 0($t7)
.end_macro

.macro BARSUB (%barID, %delta)
    li      $t9, %barID
    srl     $t8, $t9, 4
    andi    $t9, $t9, 0xF
    sll     $t8, $t8, 2
    add     $t8, $t8, $t9
    la      $t7, bar_state
    add     $t7, $t7, $t8
    lbu     $at, 0($t7)
    subi    $at, $at, %delta
    bgez    $at, _bsu_store
    li      $at, 0
_bsu_store:
    sb      $at, 0($t7)
.end_macro

.macro BARCHK (%barID, %thresh, %label)
    li      $t9, %barID
    srl     $t8, $t9, 4
    andi    $t9, $t9, 0xF
    sll     $t8, $t8, 2
    add     $t8, $t8, $t9
    la      $t7, bar_state
    add     $t7, $t7, $t8
    lbu     $at, 0($t7)
    bge     $at, %thresh, %label
.end_macro

.macro BARRND (%barID, %lo, %hi)
    li      $v0, SYS_RAND_RANGE
    li      $a0, 0
    li      $a1, %hi
    subi    $a1, $a1, %lo
    addi    $a1, $a1, 1
    syscall
    addi    $a0, $a0, %lo
    li      $t9, %barID
    srl     $t8, $t9, 4
    andi    $t9, $t9, 0xF
    sll     $t8, $t8, 2
    add     $t8, $t8, $t9
    la      $t7, bar_state
    add     $t7, $t7, $t8
    sb      $a0, 0($t7)
.end_macro

###############################################################################
# SECTION 3 - DATA SEGMENT
###############################################################################

    .data

# ---- Framebuffer (must be first so it lands at 0x10010000) ----
framebuffer:
    .space 65536

# ---- Player state ----
bar_state:
    .byte  50, 30, 40, 60               # Vampires
    .byte  50, 70, 80, 30               # Miners
    .byte  50, 20, 50, 80               # Priests
    .byte  50, 10, 30, 20               # Lithari

flags:
    .byte  0

last_choice:
    .byte  0                            # 1=A, 2=B, 3=C (last choice made)

    .align 2

# ---- Speaker -> portrait map ----
speaker_to_img:
    .word  0                            # 0: NARR (special)
    .word  img_advisor                  # 1: ADV
    .word  img_edmure                   # 2: EDM
    .word  img_grimor                   # 3: GRM
    .word  img_thomas                   # 4: THM
    .word  img_valar                    # 5: VAL
    .word  img_lithos                  # 6: LIT (portrait, after dream env set)
    .word  0                            # 7: YOU (special)
    .word  img_chamber_night            # 8: GUARD/MNR
    .word  img_chamber_night            # 9: dream-context speaker

# ---- Env table (indexed by env_code - 0xE0) ----
env_images:
    .word  img_throne_room              # ENV_THRONE     (0xE0)
    .word  img_dream_lithos             # ENV_DREAM      (0xE1)
    .word  img_chamber_night            # ENV_CHAMBER    (0xE2)
    .word  img_library                  # ENV_LIBRARY    (0xE3)
    .word  img_castle_gate              # ENV_GATE       (0xE4)
    .word  img_end_deliverance          # ENV_END_DELIV  (0xE5)
    .word  img_end_eternal_night        # ENV_END_NIGHT  (0xE6)
    .word  img_end_red_throne           # ENV_END_RED    (0xE7)
    .word  img_end_crystal_heart        # ENV_END_CRYSTAL(0xE8)
    .word  img_blood_drop               # ENV_BLOOD      (0xE9)
    .word  img_crystal_shard            # ENV_SHARD      (0xEA)
    .word  img_black_fade               # ENV_BLACK      (0xEB)

current_env:
    .word  img_throne_room

