###############################################################################
# SECTION 4 - TEXT SEGMENT
###############################################################################

    .text
    .globl main

# ============================================================================
# main - entry point and master flow
# ============================================================================
main:
    li      $v0, SYS_PRINT_STR
    la      $a0, str_title
    syscall
    la      $a0, str_title2
    syscall
    la      $a0, str_title3
    syscall

    # Randomize starting bars
    BARRND  BAR_VAMP_HUNGER,  40, 60
    BARRND  BAR_MINER_HEALTH, 40, 60
    BARRND  BAR_PRIEST_FAITH, 40, 60
    BARRND  BAR_LITH_CRYSTAL, 40, 60

# ---- DAY 1 ----
day1:
    li      $a0, 1
    jal     print_day_header
    la      $a0, day1_speakers
    la      $a1, day1_strings
    jal     run_scene

# ---- DAY 2 ----
day2:
    li      $a0, 2
    jal     print_day_header

    # Court intro
    la      $a0, day2_court_speakers
    la      $a1, day2_court_strings
    jal     run_scene

    # Choice C1
    li      $v0, SYS_PRINT_STR
    la      $a0, str_choice_hdr
    syscall
    la      $a0, d2_choice1_q
    syscall
    la      $a0, d2_choice1_a
    syscall
    la      $a0, d2_choice1_b
    syscall

    li      $a0, 2                  # 2-option choice (A/B)
    jal     read_choice_ab
    move    $s0, $v0                # save choice in $s0

    li      $t0, 1
    beq     $s0, $t0, day2_choice_a
    # else choice B
    jal     flag_set_lithari_backed
    # Bar updates for B
    BARADD  BAR_LITH_INFL, 15
    BARSUB  BAR_PRIEST_INFL, 10
    # Show speaker VAL, line d2_after_b, then night B
    li      $a0, 5                  # VAL
    la      $a1, d2_after_b
    jal     show_line
    # Night B
    li      $a0, 6                  # LIT (uses dream env)
    li      $t9, -31                # ENV_DREAM
    jal     change_env_byte
    li      $a0, 6
    la      $a1, d2_n_b
    jal     show_line
    j       day3

day2_choice_a:
    jal     flag_set_rahip_backed
    BARADD  BAR_PRIEST_INFL, 10
    BARSUB  BAR_LITH_INFL, 15
    BARSUB  BAR_MINER_INFL, 5
    li      $a0, 4                  # THM
    la      $a1, d2_after_a
    jal     show_line
    # Night A: cart, scream, shard
    li      $t9, -28                # ENV_GATE
    jal     change_env_byte
    li      $a0, 0                  # NARR
    la      $a1, d2_n_a
    jal     show_line
    # No fall-through needed; flow continues to day3

# ---- DAY 3 ----
day3:
    li      $a0, 3
    jal     print_day_header

    la      $a0, day3_intro_speakers
    la      $a1, day3_intro_strings
    jal     run_scene

    # Check if option C is unlocked (RAHIP_BACKED or LITHARI_BACKED)
    la      $t0, flags
    lbu     $t1, 0($t0)
    andi    $t2, $t1, F_RAHIP_BACKED
    bnez    $t2, day3_unlock_rahip
    andi    $t2, $t1, F_LITHARI_BACKED
    bnez    $t2, day3_unlock_lith
    j       day3_present_choice     # no unlock, A/B only

day3_unlock_rahip:
    li      $a0, 4                  # THM
    la      $a1, d3_l04_rahip
    jal     show_line
    j       day3_present_choice_abc

day3_unlock_lith:
    li      $a0, 5                  # VAL
    la      $a1, d3_l04_lith
    jal     show_line
    j       day3_present_choice_abc

day3_present_choice:
    # 2-option choice (A/B)
    li      $v0, SYS_PRINT_STR
    la      $a0, str_choice_hdr
    syscall
    la      $a0, d3_choice_q
    syscall
    la      $a0, d3_choice_a
    syscall
    la      $a0, d3_choice_b
    syscall
    li      $a0, 2
    jal     read_choice_ab
    move    $s0, $v0
    j       day3_dispatch

day3_present_choice_abc:
    # 3-option choice (A/B/C)
    li      $v0, SYS_PRINT_STR
    la      $a0, str_choice_hdr
    syscall
    la      $a0, d3_choice_q
    syscall
    la      $a0, d3_choice_a
    syscall
    la      $a0, d3_choice_b
    syscall
    la      $a0, d3_choice_c
    syscall
    li      $a0, 3
    jal     read_choice_abc
    move    $s0, $v0

day3_dispatch:
    li      $t0, 1
    beq     $s0, $t0, day3_choice_a
    li      $t0, 2
    beq     $s0, $t0, day3_choice_b
    j       day3_choice_c

day3_choice_a:
    # Grant blood tax: VAMP_PATH
    jal     flag_set_vamp_path
    BARSUB  BAR_VAMP_HUNGER, 30
    BARADD  BAR_VAMP_AGGR,   10
    BARADD  BAR_VAMP_INFL,   15
    BARSUB  BAR_MINER_HEALTH, 20
    BARSUB  BAR_MINER_STR,    15
    li      $a0, 2                  # EDM
    la      $a1, d3_after_a
    jal     show_line
    # Night A: Grimor murdered
    li      $t9, -30                # ENV_CHAMBER
    jal     change_env_byte
    li      $a0, 9                  # MINER (uses chamber env)
    la      $a1, d3_n_a
    jal     show_line
    j       day4

day3_choice_b:
    # Defer
    BARADD  BAR_VAMP_HUNGER, 5
    BARADD  BAR_VAMP_AGGR,   5
    li      $a0, 2                  # EDM
    la      $a1, d3_after_b
    jal     show_line
    # Night B: young vampire kills, Edmure asks cover-up
    li      $t9, -30                # ENV_CHAMBER
    jal     change_env_byte
    li      $a0, 2                  # EDM
    la      $a1, d3_n_b1
    jal     show_line

    # Choice C3: cover up or refuse
    li      $v0, SYS_PRINT_STR
    la      $a0, str_choice_hdr
    syscall
    la      $a0, d3_n_b_q
    syscall
    la      $a0, d3_n_b_qa
    syscall
    la      $a0, d3_n_b_qb
    syscall
    li      $a0, 2
    jal     read_choice_ab
    move    $s1, $v0

    li      $t0, 1
    beq     $s1, $t0, day3_c3_cover

    # Refuse - EDMURE_PATH
    jal     flag_set_edmure_path
    BARADD  BAR_VAMP_AGGR, 20
    j       day4

day3_c3_cover:
    # Cover up - strengthen VAMP_PATH
    jal     flag_set_vamp_path
    BARADD  BAR_VAMP_INFL, 10
    BARSUB  BAR_VAMP_AGGR, 10
    j       day4

day3_choice_c:
    # Abolish the tax
    BARADD  BAR_VAMP_HUNGER, 40
    BARADD  BAR_VAMP_AGGR,   25
    BARSUB  BAR_VAMP_INFL,   20
    li      $a0, 2                  # EDM
    la      $a1, d3_after_c
    jal     show_line
    # Night C: gates desert
    li      $t9, -28                # ENV_GATE
    jal     change_env_byte
    li      $a0, 0                  # NARR
    la      $a1, d3_n_c1
    jal     show_line
    li      $a0, 2                  # EDM
    la      $a1, d3_n_c2
    jal     show_line
    li      $a0, 4                  # THM
    la      $a1, d3_n_c3
    jal     show_line

    # Was LITHARI_BACKED chosen? Then we go to "night with Lithos" path instead
    la      $t0, flags
    lbu     $t1, 0($t0)
    andi    $t2, $t1, F_LITHARI_BACKED
    bnez    $t2, day3_lith_path

    # Otherwise: ask if accept Thomas's offer of priest guards
    li      $v0, SYS_PRINT_STR
    la      $a0, str_choice_hdr
    syscall
    la      $a0, d3_n_c_q
    syscall
    la      $a0, d3_n_b_qa          # reuse "Accept" wording
    syscall
    la      $a0, d3_n_b_qb          # reuse "Refuse" wording
    syscall
    li      $a0, 2
    jal     read_choice_ab
    move    $s1, $v0
    li      $t0, 1
    bne     $s1, $t0, day4          # refused
    # accepted Thomas's guards
    BARADD  BAR_PRIEST_INFL, 20
    BARADD  BAR_PRIEST_STR,  15
    j       day4

day3_lith_path:
    # Night with Lithos
    li      $a0, 0                  # NARR
    la      $a1, d3_n_d
    jal     show_line
    BARADD  BAR_LITH_CRYSTAL, 15
    BARADD  BAR_LITH_INFL,    15
    j       day4

# ---- DAY 4 ----
day4:
    li      $a0, 4
    jal     print_day_header

    la      $a0, day4_intro_speakers
    la      $a1, day4_intro_strings
    jal     run_scene

    # If VAMP_PATH, Edmure delivers private warning
    la      $t0, flags
    lbu     $t1, 0($t0)
    andi    $t2, $t1, F_VAMP_PATH
    beqz    $t2, day4_skip_warning
    li      $a0, 2                  # EDM
    la      $a1, d4_l04_vamp
    jal     show_line
day4_skip_warning:

    # Choice C4: grant or refuse dig
    li      $v0, SYS_PRINT_STR
    la      $a0, str_choice_hdr
    syscall
    la      $a0, d4_choice_q
    syscall
    la      $a0, d4_choice_a
    syscall
    la      $a0, d4_choice_b
    syscall
    li      $a0, 2
    jal     read_choice_ab
    move    $s0, $v0

    li      $t0, 1
    beq     $s0, $t0, day4_grant
    # Refuse the dig
    jal     flag_set_lithari_path
    BARADD  BAR_LITH_CRYSTAL, 20
    BARADD  BAR_LITH_INFL,    15
    BARSUB  BAR_PRIEST_INFL,  20
    j       day4_night

day4_grant:
    jal     flag_set_rahip_path
    BARADD  BAR_PRIEST_INFL, 25
    BARADD  BAR_PRIEST_FAITH, 20
    BARSUB  BAR_LITH_INFL,   30
    BARSUB  BAR_LITH_CRYSTAL, 20

day4_night:
    # Library scene
    la      $a0, day4_night_speakers
    la      $a1, day4_night_strings
    jal     run_scene

    # Choice C5: keep or burn the book
    li      $v0, SYS_PRINT_STR
    la      $a0, str_choice_hdr
    syscall
    la      $a0, d4_n_choice_q
    syscall
    la      $a0, d4_n_choice_a
    syscall
    la      $a0, d4_n_choice_b
    syscall
    li      $a0, 2
    jal     read_choice_ab
    move    $s0, $v0

    li      $t0, 2
    bne     $s0, $t0, day4_keep_book

    # Try to burn - only allowed if LITHARI_BACKED
    la      $t0, flags
    lbu     $t1, 0($t0)
    andi    $t2, $t1, F_LITHARI_BACKED
    bnez    $t2, day4_burn_ok

    # Locked - force keep
    li      $a0, 0                  # NARR
    la      $a1, d4_n_locked
    jal     show_line
    j       day4_keep_book

day4_burn_ok:
    jal     flag_set_book_burned
    BARSUB  BAR_PRIEST_INFL, 50
    BARSUB  BAR_PRIEST_STR,  30
    li      $a0, 0                  # NARR
    la      $a1, d4_n_after_b
    jal     show_line
    j       day5_resolver

day4_keep_book:
    jal     flag_set_book_kept
    BARADD  BAR_PRIEST_INFL, 20
    li      $a0, 7                  # YOU
    la      $a1, d4_n_after_a
    jal     show_line
    j       day5_resolver

# ---- DAY 5 ENDING RESOLVER ----
# Priority:
#   1. BOOK_KEPT -> Ending I
#   2. BOOK_BURNED + VAMP_PATH -> Day 5 Vamp branch (Ending II or III)
#   3. BOOK_BURNED + LITHARI_PATH -> Ending IV
#   4. fallback -> Ending I
day5_resolver:
    li      $a0, 5
    jal     print_day_header

    la      $t0, flags
    lbu     $t1, 0($t0)

    andi    $t2, $t1, F_BOOK_KEPT
    bnez    $t2, ending_I

    andi    $t2, $t1, F_BOOK_BURNED
    beqz    $t2, ending_I            # no burn -> default

    # Book burned - check paths
    andi    $t2, $t1, F_VAMP_PATH
    bnez    $t2, day5_vamp_branch

    andi    $t2, $t1, F_LITHARI_PATH
    bnez    $t2, ending_IV

    # Fallback
    j       ending_I

# ---- Day 5 Vampire branch ----
day5_vamp_branch:
    la      $a0, end2_intro_speakers
    la      $a1, end2_intro_strings
    jal     run_scene

    li      $v0, SYS_PRINT_STR
    la      $a0, str_choice_hdr
    syscall
    la      $a0, e2_choice_q
    syscall
    la      $a0, e2_choice_a
    syscall
    la      $a0, e2_choice_b
    syscall
    li      $a0, 2
    jal     read_choice_ab
    move    $s0, $v0

    li      $t0, 1
    beq     $s0, $t0, ending_II
    j       ending_III

# ============================================================================
# ENDINGS
# ============================================================================
ending_I:
    la      $a0, end1_speakers
    la      $a1, end1_strings
    jal     run_scene
    j       game_over

ending_II:
    la      $a0, end2a_speakers
    la      $a1, end2a_strings
    jal     run_scene
    j       game_over

ending_III:
    la      $a0, end2b_speakers
    la      $a1, end2b_strings
    jal     run_scene
    j       game_over

ending_IV:
    la      $a0, end4_speakers
    la      $a1, end4_strings
    jal     run_scene
    j       game_over

# ============================================================================
# game_over - clean exit
# ============================================================================
game_over:
    li      $v0, SYS_PRINT_STR
    la      $a0, str_end_banner
    syscall
    la      $a0, str_end_banner2
    syscall
    la      $a0, str_end_banner
    syscall
    la      $a0, str_thanks
    syscall
    li      $v0, SYS_EXIT
    syscall

###############################################################################
# HELPERS
###############################################################################

# ============================================================================
# print_day_header($a0 = day number)
# ============================================================================
print_day_header:
    move    $t0, $a0
    li      $v0, SYS_PRINT_STR
    la      $a0, str_day_label
    syscall
    li      $v0, SYS_PRINT_INT
    move    $a0, $t0
    syscall
    li      $v0, SYS_PRINT_STR
    la      $a0, str_day_end
    syscall
    jr      $ra

# ============================================================================
# run_scene($a0 = speakers ptr, $a1 = strings ptr)
# Walks parallel arrays of (byte speaker, word string). Special codes:
#   0xE0..0xEB = env switch
#   0xFF       = end
#   0          = NARR (use current env)
#   7          = YOU (use current env)
#   1..6, 8, 9 = portrait speakers
# ============================================================================
run_scene:
    addi    $sp, $sp, -16
    sw      $ra, 0($sp)
    sw      $s0, 4($sp)
    sw      $s1, 8($sp)
    sw      $s2, 12($sp)

    move    $s0, $a0
    move    $s1, $a1

scene_loop:
    lb      $s2, 0($s0)              # signed load (so 0xFF -> -1)

    # End sentinel?
    li      $t0, -1
    beq     $s2, $t0, scene_done

    # Env switch? (-32..-21, i.e. 0xE0..0xEB)
    li      $t0, -32
    blt     $s2, $t0, sl_dialog
    li      $t0, -21
    bgt     $s2, $t0, sl_dialog

    # Env switch path: compute env_images[(code+32) word offset]
    addi    $t0, $s2, 32             # 0..11
    sll     $t0, $t0, 2
    la      $t1, env_images
    add     $t1, $t1, $t0
    lw      $a0, 0($t1)
    la      $t1, current_env
    sw      $a0, 0($t1)
    jal     blit_image
    j       sl_advance

sl_dialog:
    # Normal dialog. $s2 is in 0..9 range.
    # Speakers 0 (NARR) and 7 (YOU): keep current_env.
    # Speaker 6 (LIT): use dream env.
    # Others: use portrait.
    li      $t0, 0
    beq     $s2, $t0, sl_use_env
    li      $t0, 7
    beq     $s2, $t0, sl_use_env

    sll     $t0, $s2, 2
    la      $t1, speaker_to_img
    add     $t1, $t1, $t0
    lw      $a0, 0($t1)
    jal     blit_image
    j       sl_print

sl_use_env:
    la      $t1, current_env
    lw      $a0, 0($t1)
    jal     blit_image

sl_print:
    li      $v0, SYS_PRINT_STR
    la      $a0, str_speaker_open
    syscall
    sll     $t0, $s2, 2
    la      $t1, speaker_names
    add     $t1, $t1, $t0
    lw      $a0, 0($t1)
    li      $v0, SYS_PRINT_STR
    syscall
    la      $a0, str_speaker_close
    li      $v0, SYS_PRINT_STR
    syscall
    lw      $a0, 0($s1)
    li      $v0, SYS_PRINT_STR
    syscall
    jal     wait_enter

sl_advance:
    addi    $s0, $s0, 1
    addi    $s1, $s1, 4
    j       scene_loop

scene_done:
    lw      $ra, 0($sp)
    lw      $s0, 4($sp)
    lw      $s1, 8($sp)
    lw      $s2, 12($sp)
    addi    $sp, $sp, 16
    jr      $ra

# ============================================================================
# show_line($a0 = speaker code, $a1 = string addr)
# Quick helper to print one line outside a scene script.
# ============================================================================
show_line:
    addi    $sp, $sp, -12
    sw      $ra, 0($sp)
    sw      $s0, 4($sp)
    sw      $s1, 8($sp)
    move    $s0, $a0
    move    $s1, $a1

    # Pick image
    li      $t0, 0
    beq     $s0, $t0, sln_use_env
    li      $t0, 7
    beq     $s0, $t0, sln_use_env
    sll     $t0, $s0, 2
    la      $t1, speaker_to_img
    add     $t1, $t1, $t0
    lw      $a0, 0($t1)
    jal     blit_image
    j       sln_print
sln_use_env:
    la      $t1, current_env
    lw      $a0, 0($t1)
    jal     blit_image
sln_print:
    li      $v0, SYS_PRINT_STR
    la      $a0, str_speaker_open
    syscall
    sll     $t0, $s0, 2
    la      $t1, speaker_names
    add     $t1, $t1, $t0
    lw      $a0, 0($t1)
    li      $v0, SYS_PRINT_STR
    syscall
    la      $a0, str_speaker_close
    li      $v0, SYS_PRINT_STR
    syscall
    move    $a0, $s1
    li      $v0, SYS_PRINT_STR
    syscall
    jal     wait_enter

    lw      $ra, 0($sp)
    lw      $s0, 4($sp)
    lw      $s1, 8($sp)
    addi    $sp, $sp, 12
    jr      $ra

# ============================================================================
# change_env_byte($t9 = signed env code, e.g. -32 for ENV_THRONE)
# Manually switch current_env from inside main flow (not via scene script).
# ============================================================================
change_env_byte:
    addi    $sp, $sp, -4
    sw      $ra, 0($sp)
    addi    $t0, $t9, 32
    sll     $t0, $t0, 2
    la      $t1, env_images
    add     $t1, $t1, $t0
    lw      $a0, 0($t1)
    la      $t1, current_env
    sw      $a0, 0($t1)
    jal     blit_image
    lw      $ra, 0($sp)
    addi    $sp, $sp, 4
    jr      $ra

# ============================================================================
# blit_image($a0 = src) - copies 16384 words to framebuffer
# ============================================================================
blit_image:
    move    $t0, $a0
    la      $t1, framebuffer
    li      $t2, IMG_WORDS
blit_loop:
    lw      $t3, 0($t0)
    lw      $t4, 4($t0)
    lw      $t5, 8($t0)
    lw      $t6, 12($t0)
    sw      $t3, 0($t1)
    sw      $t4, 4($t1)
    sw      $t5, 8($t1)
    sw      $t6, 12($t1)
    addi    $t0, $t0, 16
    addi    $t1, $t1, 16
    subi    $t2, $t2, 4
    bgtz    $t2, blit_loop
    jr      $ra

# ============================================================================
# wait_enter - reads chars until newline
# ============================================================================
wait_enter:
    li      $v0, SYS_PRINT_STR
    la      $a0, str_press_enter
    syscall
we_loop:
    li      $v0, SYS_READ_CHAR
    syscall
    li      $t0, 10
    bne     $v0, $t0, we_loop
    jr      $ra

# ============================================================================
# read_choice_ab - returns 1 (A) or 2 (B) in $v0
# read_choice_abc - returns 1, 2, or 3 in $v0
# ============================================================================
read_choice_ab:
    li      $t9, 2
    j       rc_common
read_choice_abc:
    li      $t9, 3
rc_common:
    li      $v0, SYS_PRINT_STR
    la      $a0, str_prompt_choice
    syscall
rc_read:
    li      $v0, SYS_READ_CHAR
    syscall
    move    $t0, $v0
    # skip newlines and CR
    li      $t1, 10
    beq     $t0, $t1, rc_read
    li      $t1, 13
    beq     $t0, $t1, rc_read
    # lowercase -> uppercase
    li      $t1, 'a'
    blt     $t0, $t1, rc_chk_upper
    li      $t1, 'c'
    bgt     $t0, $t1, rc_invalid
    subi    $t0, $t0, 32
rc_chk_upper:
    li      $t1, 'A'
    blt     $t0, $t1, rc_invalid
    li      $t1, 'C'
    bgt     $t0, $t1, rc_invalid
    subi    $t0, $t0, 64             # 'A' -> 1
    bgt     $t0, $t9, rc_invalid
    move    $v0, $t0
    jr      $ra
rc_invalid:
    li      $v0, SYS_PRINT_STR
    la      $a0, str_invalid_choice
    syscall
    j       rc_read

# ============================================================================
# Flag setters (each one ORs its bit into flags)
# ============================================================================
flag_set_rahip_backed:
    la      $t0, flags
    lbu     $t1, 0($t0)
    ori     $t1, $t1, F_RAHIP_BACKED
    sb      $t1, 0($t0)
    jr      $ra

flag_set_lithari_backed:
    la      $t0, flags
    lbu     $t1, 0($t0)
    ori     $t1, $t1, F_LITHARI_BACKED
    sb      $t1, 0($t0)
    jr      $ra

flag_set_vamp_path:
    la      $t0, flags
    lbu     $t1, 0($t0)
    ori     $t1, $t1, F_VAMP_PATH
    sb      $t1, 0($t0)
    jr      $ra

flag_set_rahip_path:
    la      $t0, flags
    lbu     $t1, 0($t0)
    ori     $t1, $t1, F_RAHIP_PATH
    sb      $t1, 0($t0)
    jr      $ra

flag_set_lithari_path:
    la      $t0, flags
    lbu     $t1, 0($t0)
    ori     $t1, $t1, F_LITHARI_PATH
    sb      $t1, 0($t0)
    jr      $ra

flag_set_edmure_path:
    la      $t0, flags
    lbu     $t1, 0($t0)
    ori     $t1, $t1, F_EDMURE_PATH
    sb      $t1, 0($t0)
    jr      $ra

flag_set_book_kept:
    la      $t0, flags
    lbu     $t1, 0($t0)
    ori     $t1, $t1, F_BOOK_KEPT
    sb      $t1, 0($t0)
    jr      $ra

flag_set_book_burned:
    la      $t0, flags
    lbu     $t1, 0($t0)
    ori     $t1, $t1, F_BOOK_BURNED
    sb      $t1, 0($t0)
    jr      $ra

###############################################################################
# END OF game.asm
###############################################################################
